                    if not sid:
                        continue
                    indexed_sids.add(sid)
                    full_path = entry.get("fullPath")
                    p = Path(full_path) if full_path else None
                    if p and p.exists():
                        paths.append(p)
                    else:
                        p = project_dir / f"{sid}.jsonl"
                        if p.exists():
                            paths.append(p)
